import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import './ValorantPage.css';
import Header from './Header';

function ValorantPage() {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    contact: ''
  });

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log('Новое объявление:', formData);
    alert('Объявление размещено!');
    setIsModalOpen(false);
    setFormData({ title: '', description: '', contact: '' });
  };

  return (
    <div className="valorant-page">
      <Header />
      <div className="valorant-content">
        <h1>VALORANT</h1>
        <p>Valorant — это динамичный тактический шутер, где молниеносная стрельба переплетается с уникальными способностями агентов, превращая каждый раунд в захватывающее противостояние умов и реакции.</p>
        {/* Кнопка удалена */}
      </div>
            <div className="announcement-wrapper">
        <div className="valorant-announcements">
          <div className="announcement-item">Объявление 1</div>
          <div className="announcement-item">Объявление 2</div>
          <div className="announcement-item">Объявление 3</div>
          <div className="announcement-item">Объявление 4</div>
          <div className="announcement-item">Объявление 5</div>
        </div>
        <button className="add-announcement-btn" onClick={() => setIsModalOpen(true)}>
          Разместить объявление
        </button>
      </div>
      {isModalOpen && (
        <div className="modal-overlay" onClick={() => setIsModalOpen(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <h2>Новое объявление</h2>
            <form onSubmit={handleSubmit}>
              <label>
                Заголовок
                <input type="text" name="title" value={formData.title} onChange={handleChange} placeholder="Введите заголовок" required />
              </label>
              <label>
                Описание
                <textarea name="description" value={formData.description} onChange={handleChange} placeholder="Опишите, кого ищете" rows="4" required />
              </label>
              <label>
                Контактные данные
                <input type="text" name="contact" value={formData.contact} onChange={handleChange} placeholder="Discord, Telegram или другой способ связи" required />
              </label>
              <div className="modal-buttons">
                <button type="submit" className="submit-btn">Опубликовать</button>
                <button type="button" className="cancel-btn" onClick={() => setIsModalOpen(false)}>Отмена</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

export default ValorantPage;
